"""Read-only readiness assessment for the Claude→Codex migration family."""

from __future__ import annotations

import argparse
import importlib.util
import json
import sys
from pathlib import Path


def _find_repo_root() -> Path:
    p = Path(__file__).resolve().parent
    while p != p.parent:
        if (p / ".git").exists() or (p / "package.json").exists():
            return p
        p = p.parent
    raise RuntimeError("Repository root not found")


REPO_ROOT = _find_repo_root()
MIGRATOR_PATH = Path(__file__).with_name("migrate_claude_workflows_to_codex.py")
VALIDATOR_PATH = (
    REPO_ROOT
    / ".codex"
    / "skills"
    / "verify-skill-migration"
    / "scripts"
    / "validate_skill_migration.py"
)
DASHBOARD_PATH = (
    REPO_ROOT
    / ".codex"
    / "skills"
    / "migration-dashboard"
    / "scripts"
    / "analyze_migration.py"
)


def _load_module(module_name: str, path: Path):
    spec = importlib.util.spec_from_file_location(module_name, path)
    if spec is None or spec.loader is None:
        raise RuntimeError(f"Unable to load module from {path}")
    module = importlib.util.module_from_spec(spec)
    sys.modules[module_name] = module
    spec.loader.exec_module(module)
    return module


migrator = _load_module("migration_doctor_migrator", MIGRATOR_PATH)
validator = _load_module("migration_doctor_validator", VALIDATOR_PATH)
dashboard = _load_module("migration_doctor_dashboard", DASHBOARD_PATH)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Read-only readiness assessment for Codex migration work."
    )
    group = parser.add_mutually_exclusive_group()
    group.add_argument("--skill", type=str, help="Assess one source skill by name.")
    group.add_argument(
        "--all",
        action="store_true",
        dest="all_skills",
        help="Assess every non-archived source skill (default).",
    )
    parser.add_argument(
        "--json",
        action="store_true",
        dest="json_output",
        help="Emit structured JSON instead of human-readable text.",
    )
    return parser.parse_args()


def _resolve_skill_scope(skill: str | None) -> list[str]:
    if skill:
        source_dir = migrator.SOURCE_SKILLS_DIR / skill
        if not source_dir.exists():
            raise FileNotFoundError(f"Source skill not found: {source_dir}")
        return [skill]
    return [path.name for path in migrator.iter_source_skill_dirs()]


def _package_size_bytes(path: Path) -> int:
    return sum(file.stat().st_size for file in path.rglob("*") if file.is_file())


def _skill_line_count(skill_dir: Path) -> int:
    skill_md = skill_dir / "SKILL.md"
    if not skill_md.exists():
        return 0
    with skill_md.open("r", encoding="utf-8") as handle:
        return sum(1 for _ in handle)


def _validate_scan_dir(scan_dir: Path) -> dict[str, object]:
    if not scan_dir.exists():
        return {"passed": None, "errors": [], "warnings": []}

    scan_dirs = (scan_dir,)
    markdown_files = validator.collect_markdown_files(scan_dirs)
    skill_files = validator.collect_skill_entrypoints(scan_dirs)
    errors: list[str] = []
    warnings: list[str] = []

    for check_fn in validator.CHECKS.values():
        check_errors, check_warnings = check_fn(scan_dirs, markdown_files, skill_files)
        errors.extend(check_errors)
        warnings.extend(check_warnings)

    return {"passed": not errors, "errors": errors, "warnings": warnings}


def _safe_load_tracker() -> tuple[dict | None, str | None]:
    try:
        return dashboard.load_tracker(), None
    except (OSError, ValueError, json.JSONDecodeError) as exc:
        return None, str(exc)


def _build_summary(skill_reports: list[dict[str, object]]) -> dict[str, object]:
    summary = {
        "skills_considered": len(skill_reports),
        "mechanical_safe": 0,
        "blocked": 0,
        "manual_review_required": 0,
        "refactor_required": 0,
        "validator_failures": 0,
        "drifted": 0,
        "oversized": 0,
        "pending_native_review": 0,
        "existing_codex_targets": 0,
    }

    for report in skill_reports:
        status = report["status"]
        if status == migrator.STATUS_MECHANICAL_SAFE:
            summary["mechanical_safe"] += 1
        elif status == migrator.STATUS_BLOCKED:
            summary["blocked"] += 1
        elif status == migrator.STATUS_MANUAL_REVIEW_REQUIRED:
            summary["manual_review_required"] += 1
        elif status == migrator.STATUS_REFACTOR_REQUIRED:
            summary["refactor_required"] += 1

        if report["target_exists"]:
            summary["existing_codex_targets"] += 1
        if report["drifted"]:
            summary["drifted"] += 1
        if report["oversized"]:
            summary["oversized"] += 1
        if report["review_state"] == "pending_native_review":
            summary["pending_native_review"] += 1

        validation = report["validation"]
        if validation["passed"] is False:
            summary["validator_failures"] += 1

    score = 100
    if summary["blocked"]:
        score -= 35 + min(summary["blocked"] * 8, 20)
    if summary["manual_review_required"]:
        score -= 20 + min(summary["manual_review_required"] * 4, 12)
    if summary["refactor_required"]:
        score -= 18 + min(summary["refactor_required"] * 4, 12)
    if summary["validator_failures"]:
        score -= 12 + min(summary["validator_failures"] * 3, 9)
    if summary["drifted"]:
        score -= 8 + min(summary["drifted"] * 2, 6)
    if summary["pending_native_review"]:
        score -= min(summary["pending_native_review"] * 2, 10)
    if summary["oversized"]:
        score -= min(summary["oversized"] * 2, 8)
    score = max(0, min(100, score))

    if summary["blocked"] or summary["manual_review_required"] or summary["refactor_required"]:
        readiness = "blocked"
        recommended_action = "stop_and_fix_dependencies"
    elif summary["validator_failures"] or summary["drifted"]:
        readiness = "needs_review"
        recommended_action = "patch_existing_codex_artifacts"
    elif summary["pending_native_review"]:
        readiness = "needs_review"
        recommended_action = "prefer_preview_then_review"
    else:
        readiness = "ready"
        recommended_action = "proceed"

    summary["score"] = score
    summary["readiness"] = readiness
    summary["recommended_action"] = recommended_action
    return summary


def _build_risks(summary: dict[str, object]) -> list[dict[str, str]]:
    risks: list[dict[str, str]] = []
    if summary["blocked"]:
        risks.append(
            {
                "severity": "high",
                "title": "Hard migration dependencies are unresolved",
                "detail": (
                    f"{summary['blocked']} skill(s) are blocked by missing named agents or "
                    "hard skill dependencies."
                ),
            }
        )
    if summary["manual_review_required"]:
        risks.append(
            {
                "severity": "high",
                "title": "Ambiguous skill references need adjudication",
                "detail": (
                    f"{summary['manual_review_required']} skill(s) require manual review before "
                    "mechanical migration is safe."
                ),
            }
        )
    if summary["refactor_required"]:
        risks.append(
            {
                "severity": "high",
                "title": "Some skills still require hand-authored migration",
                "detail": (
                    f"{summary['refactor_required']} skill(s) contain orchestration patterns that "
                    "the deterministic migrator should not flatten."
                ),
            }
        )
    if summary["validator_failures"]:
        risks.append(
            {
                "severity": "medium",
                "title": "Existing Codex artifacts already fail validation",
                "detail": (
                    f"{summary['validator_failures']} migrated skill package(s) currently fail the "
                    "migration validator."
                ),
            }
        )
    if summary["drifted"]:
        risks.append(
            {
                "severity": "medium",
                "title": "Tracker drift detected",
                "detail": (
                    f"{summary['drifted']} migrated skill package(s) changed since the last tracker "
                    "write."
                ),
            }
        )
    if summary["pending_native_review"]:
        risks.append(
            {
                "severity": "medium",
                "title": "Pending nativeness review backlog exists",
                "detail": (
                    f"{summary['pending_native_review']} migrated skill package(s) are still in "
                    "`pending_native_review`."
                ),
            }
        )
    if summary["oversized"]:
        risks.append(
            {
                "severity": "low",
                "title": "Oversized skill packages detected",
                "detail": (
                    f"{summary['oversized']} package(s) exceed the size or line-count heuristic "
                    "used by the doctor."
                ),
            }
        )
    return risks


def build_doctor_report(skill: str | None = None) -> dict[str, object]:
    skills = _resolve_skill_scope(skill)
    tracker_data, tracker_error = _safe_load_tracker()
    tracker_present = tracker_data is not None
    drifted_skills = (
        {
            item["name"]
            for item in dashboard.detect_drift(tracker_data.get("artifacts", []))
            if item.get("artifact_type") == "skill"
        }
        if tracker_present
        else set()
    )
    tracker_artifacts = {
        artifact.get("name"): artifact
        for artifact in (tracker_data or {}).get("artifacts", [])
        if artifact.get("artifact_type") == "skill"
    }
    skill_reports: list[dict[str, object]] = []

    for skill_name in skills:
        source_dir = migrator.SOURCE_SKILLS_DIR / skill_name
        classification = migrator.classify_skill(source_dir)
        target_dir = migrator.TARGET_SKILLS_DIR / skill_name
        target_exists = target_dir.exists()
        validation = _validate_scan_dir(target_dir)
        tracker_artifact = tracker_artifacts.get(skill_name)
        line_count = _skill_line_count(target_dir) if target_exists else 0
        package_size_bytes = _package_size_bytes(target_dir) if target_exists else 0
        oversized = (
            line_count >= validator.LINE_COUNT_WARNING_THRESHOLD
            or package_size_bytes > 32768
        )

        skill_reports.append(
            {
                "skill": skill_name,
                "status": classification.status,
                "target_exists": target_exists,
                "review_state": (
                    tracker_artifact.get("review", {}).get("state", "not_applicable")
                    if tracker_artifact
                    else "not_applicable"
                ),
                "drifted": skill_name in drifted_skills,
                "oversized": oversized,
                "line_count": line_count,
                "package_size_bytes": package_size_bytes,
                "findings": [migrator.asdict(finding) for finding in classification.findings],
                "missing_agents": classification.missing_agents,
                "missing_skills": classification.missing_skills,
                "ambiguous_references": [
                    migrator.asdict(reference)
                    for reference in classification.ambiguous_references
                ],
                "validation": validation,
            }
        )

    summary = _build_summary(skill_reports)
    environment_readiness = validator.build_environment_readiness_report()
    summary["environment_readiness_state"] = environment_readiness["state"]
    summary["environment_readiness_failures"] = environment_readiness["failures"]
    summary["environment_readiness_warnings"] = environment_readiness["warnings"]
    report = {
        "mode": "skill_migration_doctor",
        "scope": {
            "skill": skill,
            "all_skills": skill is None,
            "tracker_present": tracker_present,
            "tracker_error": tracker_error,
        },
        "summary": summary,
        "items": skill_reports,
        "blockers": [],
        "risks": _build_risks(summary),
        "skills": skill_reports,
        "environment_readiness": environment_readiness,
    }
    if summary["readiness"] == "blocked":
        report["next_actions"] = ["Resolve blockers or manual-review items before rerunning migration."]
    elif summary["readiness"] == "needs_review":
        report["next_actions"] = ["Preview the target skill and patch existing Codex artifacts before live migration."]
    else:
        report["next_actions"] = ["Proceed with preview or live migration depending on the user's requested scope."]
    if tracker_error:
        report["risks"].append(
            {
                "severity": "medium",
                "title": "Tracker data could not be loaded",
                "detail": f"Proceed without drift/review context until the tracker is repaired: {tracker_error}",
            }
        )
    if environment_readiness["state"] == "failed":
        report["risks"].append(
            {
                "severity": "medium",
                "title": "Environment readiness failed",
                "detail": (
                    f"{environment_readiness['failures']} environment readiness check(s) failed. "
                    "Skill migration may still proceed, but runtime setup needs attention."
                ),
            }
        )
    elif environment_readiness["state"] == "warnings":
        report["risks"].append(
            {
                "severity": "low",
                "title": "Environment readiness has warnings",
                "detail": (
                    f"{environment_readiness['warnings']} environment readiness warning(s) were found. "
                    "Review them before relying on migrated artifacts operationally."
                ),
            }
        )
    report["blockers"] = [
        {
            "severity": risk["severity"],
            "type": "risk",
            "detail": f"{risk['title']}: {risk['detail']}",
        }
        for risk in report["risks"]
    ]
    return report


def format_doctor_report(report: dict[str, object]) -> str:
    summary = report["summary"]
    lines = [
        "Migration Doctor",
        "================",
        f"Readiness: {summary['readiness']} ({summary['score']}/100)",
        f"Recommended action: {summary['recommended_action']}",
        "",
        "Summary:",
        (
            f"  skills={summary['skills_considered']}  mechanical_safe={summary['mechanical_safe']}  "
            f"blocked={summary['blocked']}  manual_review={summary['manual_review_required']}  "
            f"refactor_required={summary['refactor_required']}"
        ),
        (
            f"  validator_failures={summary['validator_failures']}  drifted={summary['drifted']}  "
            f"pending_native_review={summary['pending_native_review']}  oversized={summary['oversized']}"
        ),
        (
            "  environment_readiness="
            f"{summary['environment_readiness_state']} "
            f"(failures={summary['environment_readiness_failures']} "
            f"warnings={summary['environment_readiness_warnings']})"
        ),
    ]

    environment_readiness = report.get("environment_readiness", {})
    environment_checks = environment_readiness.get("checks", [])
    if environment_checks:
        lines.extend(["", "Environment Readiness:"])
        for check in environment_checks[:10]:
            lines.append(
                f"  - [{check['status']}] {check['name']}: {check['detail']}"
            )
        if len(environment_checks) > 10:
            lines.append(f"  - ...and {len(environment_checks) - 10} more checks")

    risks = report["risks"]
    if risks:
        lines.extend(["", "Risks:"])
        for risk in risks:
            lines.append(f"  - [{risk['severity']}] {risk['title']}: {risk['detail']}")

    lines.extend(["", "Per Skill:"])
    for skill_report in report["skills"]:
        validation = skill_report["validation"]
        validation_state = (
            "not_scanned"
            if validation["passed"] is None
            else ("pass" if validation["passed"] else "fail")
        )
        lines.append(
            "  - "
            f"{skill_report['skill']}: status={skill_report['status']} "
            f"target_exists={skill_report['target_exists']} "
            f"review={skill_report['review_state']} "
            f"validator={validation_state}"
        )
        if skill_report["missing_agents"]:
            lines.append(
                "      missing_agents=" + ", ".join(skill_report["missing_agents"])
            )
        if skill_report["missing_skills"]:
            lines.append(
                "      missing_skills=" + ", ".join(skill_report["missing_skills"])
            )
        if skill_report["ambiguous_references"]:
            lines.append(
                f"      ambiguous_references={len(skill_report['ambiguous_references'])}"
            )
        if skill_report["drifted"]:
            lines.append("      drifted=yes")
        if skill_report["oversized"]:
            lines.append(
                "      oversized=yes "
                f"(lines={skill_report['line_count']} bytes={skill_report['package_size_bytes']})"
            )
        if validation["passed"] is False:
            for error in validation["errors"][:3]:
                lines.append(f"      validation_error={error}")

    return "\n".join(lines)


def main() -> int:
    args = parse_args()
    report = build_doctor_report(skill=args.skill)
    if args.json_output:
        print(json.dumps(report, indent=2))
    else:
        print(format_doctor_report(report))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
